from .style import ZORDER, SKY_COLORdef _draw_sky(    sky,    ax,    sky_mode="transmission",):    """    Draw a Sky object.    Parameters    ----------    sky : Sky    ax : matplotlib.axes.Axes    mode : {"transmission", "radiance"}    """    if sky_mode == "transmission":        y = sky.transmission    elif sky_mode == "radiance":        y = sky.radiance/1e9    else:        raise ValueError(            "mode must be 'transmission' or 'radiance'"        )    ax.plot(        sky.wavelength,        y,        color=SKY_COLOR[sky_mode],        lw=0.3,        zorder=ZORDER["sky"],        label=sky_mode    )            